// =============================================
// Student Report System — Mini Project
// Uses: objects, arrays, functions, arrow fns,
//       map, filter, sort, reduce, template literals
// =============================================

const students = [
    { name: "Rahul",  maths: 88, science: 75, english: 82 },
    { name: "Priya",  maths: 95, science: 91, english: 89 },
    { name: "Amit",   maths: 62, science: 55, english: 70 },
    { name: "Sneha",  maths: 78, science: 83, english: 91 },
    { name: "Vikram", maths: 45, science: 50, english: 48 },
];

const getAverage = s => (s.maths + s.science + s.english) / 3;

const getGrade = avg =>
    avg >= 90 ? "A" : avg >= 75 ? "B" : avg >= 60 ? "C" : "F";

// Enrich: add average and grade to each student object
const enriched = students
    .map(s => ({ ...s, average: getAverage(s) }))
    .map(s => ({ ...s, grade: getGrade(s.average) }))
    .sort((a, b) => b.average - a.average);

// Print ranked table
console.log("=" .repeat(52));
console.log(" STUDENT REPORT SYSTEM");
console.log("=" .repeat(52));
console.log(`  ${'Rank'} ${'Name'.padEnd(8)} ${'M'.padStart(4)} ${'S'.padStart(4)} ${'E'.padStart(4)} ${'Avg'.padStart(7)} ${'G'}`);
console.log("-".repeat(52));

enriched.forEach((s, i) => {
    const avg = s.average.toFixed(1);
    console.log(`  ${i + 1}.   ${s.name.padEnd(8)} ${s.maths.toString().padStart(4)} ${s.science.toString().padStart(4)} ${s.english.toString().padStart(4)} ${avg.padStart(7)}  ${s.grade}`);
});

// Summary
const classTotal = enriched.reduce((sum, s) => sum + s.average, 0);
const classAvg   = (classTotal / enriched.length).toFixed(1);
const passCount  = enriched.filter(s => s.average >= 40).length;
console.log("=".repeat(52));
console.log(`  Class Average : ${classAvg}`);
console.log(`  Passed        : ${passCount}/${enriched.length}`);
console.log(`  Top Student   : ${enriched[0].name}`);

