exercise.solutionCode:
const students = [
    { name: "Rahul",  maths: 88, science: 75, english: 82 },
    { name: "Priya",  maths: 95, science: 91, english: 89 },
    { name: "Amit",   maths: 62, science: 55, english: 70 },
    { name: "Sneha",  maths: 78, science: 83, english: 91 },
    { name: "Vikram", maths: 45, science: 50, english: 48 },
];

const getAverage = s => (s.maths + s.science + s.english) / 3;
const getGrade   = avg => avg >= 90 ? "A" : avg >= 75 ? "B" : avg >= 60 ? "C" : "F";
const getRemark  = grade =>
    grade === "A" ? "Excellent!" :
    grade === "B" ? "Well done!" :
    grade === "C" ? "Keep going!" : "Seek help.";

const withRemarks = students
    .map(s => ({ ...s, average: getAverage(s) }))
    .map(s => ({ ...s, grade: getGrade(s.average) }))
    .map(s => ({ ...s, remark: getRemark(s.grade) }));

withRemarks.forEach(s => console.log(`${s.name} ${s.grade} ${s.remark}`));
